/** Client validation — field errors + banner messages (phiếu thu/chi Pattern B). */

import {
  VOUCHER_DESCRIPTION_MAX_LENGTH,
  voucherDescriptionMaxLengthMessage,
} from '../components/voucher/voucherDescriptionConstants';

export type LineFieldKey = 'accountCode' | 'debitAmount';

export type LineFieldErrors = Partial<Record<LineFieldKey, string>>;

export type VoucherFieldErrors = {
  voucherDate?: string;
  customerId?: string;
  accountCode?: string;
  description?: string;
  lines?: Record<number, LineFieldErrors>;
};

export type VoucherValidateInput = {
  voucherDate: string;
  customerId?: string;
  /** Khi true — `customerId` bắt buộc (phiếu chi header). */
  requireCustomerId?: boolean;
  partnerLabel?: string;
  accountCode: string;
  description?: string;
  cashLabel: string;
  lines: Array<{ accountCode: string; debitAmount: number }>;
};

export function validateVoucherFields(input: VoucherValidateInput): {
  fieldErrors: VoucherFieldErrors;
  bannerMessages: string[];
} {
  const fieldErrors: VoucherFieldErrors = {};
  const bannerMessages: string[] = [];

  if (!input.voucherDate?.trim()) {
    const msg = 'Ngày chứng từ là bắt buộc';
    fieldErrors.voucherDate = msg;
    bannerMessages.push(msg);
  }

  if (input.requireCustomerId && !input.customerId?.trim()) {
    const label = input.partnerLabel?.trim() || 'Đối tượng';
    const msg = `${label} là bắt buộc`;
    fieldErrors.customerId = msg;
    bannerMessages.push(msg);
  }

  if (!input.accountCode?.trim()) {
    const msg = `${input.cashLabel} là bắt buộc`;
    fieldErrors.accountCode = msg;
    bannerMessages.push(msg);
  }

  if (input.description && input.description.length > VOUCHER_DESCRIPTION_MAX_LENGTH) {
    const msg = voucherDescriptionMaxLengthMessage();
    fieldErrors.description = msg;
    bannerMessages.push(msg);
  }

  if (input.lines.length === 0) {
    bannerMessages.push('Phải có ít nhất 1 dòng định khoản');
  }

  input.lines.forEach((line, i) => {
    const lineErr: LineFieldErrors = {};
    if (!line.accountCode?.trim()) {
      const msg = `Dòng ${i + 1}: chưa chọn TK đối ứng`;
      lineErr.accountCode = msg;
      bannerMessages.push(msg);
    }
    if (!(Number(line.debitAmount) > 0)) {
      const msg = `Dòng ${i + 1}: số tiền phải > 0`;
      lineErr.debitAmount = msg;
      bannerMessages.push(msg);
    }
    if (Object.keys(lineErr).length > 0) {
      fieldErrors.lines = fieldErrors.lines ?? {};
      fieldErrors.lines[i] = lineErr;
    }
  });

  return { fieldErrors, bannerMessages };
}

export function collectBannerMessages(fieldErrors: VoucherFieldErrors): string[] {
  const msgs: string[] = [];
  if (fieldErrors.voucherDate) msgs.push(fieldErrors.voucherDate);
  if (fieldErrors.customerId) msgs.push(fieldErrors.customerId);
  if (fieldErrors.accountCode) msgs.push(fieldErrors.accountCode);
  if (fieldErrors.description) msgs.push(fieldErrors.description);
  if (fieldErrors.lines) {
    Object.keys(fieldErrors.lines)
      .map(Number)
      .sort((a, b) => a - b)
      .forEach(idx => {
        const le = fieldErrors.lines![idx];
        if (le?.accountCode) msgs.push(le.accountCode);
        if (le?.debitAmount) msgs.push(le.debitAmount);
      });
  }
  return msgs;
}

/** Re-validate one header field after user edit — auto-clear when valid. */
export function validateVoucherHeaderField(
  key: 'voucherDate' | 'customerId' | 'accountCode' | 'description',
  value: string,
  cashLabel: string,
  partnerLabel?: string,
): string | undefined {
  if (key === 'voucherDate') {
    return value?.trim() ? undefined : 'Ngày chứng từ là bắt buộc';
  }
  if (key === 'customerId') {
    const label = partnerLabel?.trim() || 'Đối tượng';
    return value?.trim() ? undefined : `${label} là bắt buộc`;
  }
  if (key === 'description') {
    return value.length > VOUCHER_DESCRIPTION_MAX_LENGTH
      ? voucherDescriptionMaxLengthMessage()
      : undefined;
  }
  return value?.trim() ? undefined : `${cashLabel} là bắt buộc`;
}

export function validateLineField(
  lineIndex: number,
  key: LineFieldKey,
  line: { accountCode: string; debitAmount: number },
): string | undefined {
  if (key === 'accountCode') {
    return line.accountCode?.trim()
      ? undefined
      : `Dòng ${lineIndex + 1}: chưa chọn TK đối ứng`;
  }
  return Number(line.debitAmount) > 0
    ? undefined
    : `Dòng ${lineIndex + 1}: số tiền phải > 0`;
}

export type TamUngFieldErrors = {
  voucherDate?: string;
  customerId?: string;
  creditAccountCode?: string;
  description?: string;
  processingLevel?: string;
  lines?: Record<number, LineFieldErrors>;
};

export type TamUngValidateInput = {
  voucherDate: string;
  customerId: string;
  creditAccountCode: string;
  description: string;
  processingLevel: string;
  lines: Array<{ accountCode: string; amount: number }>;
};

export function validateTamUngFields(input: TamUngValidateInput): {
  fieldErrors: TamUngFieldErrors;
  bannerMessages: string[];
} {
  const fieldErrors: TamUngFieldErrors = {};
  const bannerMessages: string[] = [];

  if (!input.voucherDate?.trim()) {
    const msg = 'Ngày chứng từ là bắt buộc';
    fieldErrors.voucherDate = msg;
    bannerMessages.push(msg);
  }
  if (!input.customerId?.trim()) {
    const msg = 'Người tạm ứng là bắt buộc';
    fieldErrors.customerId = msg;
    bannerMessages.push(msg);
  }
  if (!input.creditAccountCode?.trim()) {
    const msg = 'TK Có (tạm ứng) là bắt buộc';
    fieldErrors.creditAccountCode = msg;
    bannerMessages.push(msg);
  }
  if (!input.description?.trim()) {
    const msg = 'Diễn giải là bắt buộc';
    fieldErrors.description = msg;
    bannerMessages.push(msg);
  } else if (input.description.length > VOUCHER_DESCRIPTION_MAX_LENGTH) {
    const msg = voucherDescriptionMaxLengthMessage();
    fieldErrors.description = msg;
    bannerMessages.push(msg);
  }
  if (!input.processingLevel?.trim()) {
    const msg = 'Mức xử lý là bắt buộc';
    fieldErrors.processingLevel = msg;
    bannerMessages.push(msg);
  }

  const validLines = input.lines.filter(l => l.accountCode?.trim() && Number(l.amount) > 0);
  if (validLines.length === 0) {
    bannerMessages.push(TAM_UNG_LINE_GENERAL_ERROR);
  }

  input.lines.forEach((line, i) => {
    const lineErr: LineFieldErrors = {};
    if (!line.accountCode?.trim()) {
      const msg = `Dòng ${i + 1}: chưa chọn TK Nợ`;
      lineErr.accountCode = msg;
      bannerMessages.push(msg);
    }
    if (!(Number(line.amount) > 0)) {
      const msg = `Dòng ${i + 1}: số tiền phải > 0`;
      lineErr.debitAmount = msg;
      bannerMessages.push(msg);
    }
    if (Object.keys(lineErr).length > 0) {
      fieldErrors.lines = fieldErrors.lines ?? {};
      fieldErrors.lines[i] = lineErr;
    }
  });

  return { fieldErrors, bannerMessages };
}

export const TAM_UNG_LINE_GENERAL_ERROR = 'Phải có ít nhất 1 dòng với TK Nợ và số tiền > 0';

export function hasValidTamUngLine(
  lines: Array<{ accountCode: string; amount: number }>,
): boolean {
  return lines.some(l => l.accountCode?.trim() && Number(l.amount) > 0);
}

/** Sau khi chèn dòng tại `insertAt` — dịch `fieldErrors.lines` xuống. */
export function insertLineFieldErrors(
  lines: VoucherFieldErrors['lines'],
  insertAt: number,
): VoucherFieldErrors['lines'] | undefined {
  if (!lines) return undefined;
  const next: Record<number, LineFieldErrors> = {};
  Object.keys(lines).forEach(key => {
    const i = Number(key);
    const newIdx = i >= insertAt ? i + 1 : i;
    next[newIdx] = lines[i];
  });
  return Object.keys(next).length > 0 ? next : undefined;
}

/** Sau khi xóa dòng `removedIndex` — reindex `fieldErrors.lines`. */
export function shiftTamUngLineFieldErrors(
  lines: TamUngFieldErrors['lines'],
  removedIndex: number,
): TamUngFieldErrors['lines'] | undefined {
  if (!lines) return undefined;
  const next: Record<number, LineFieldErrors> = {};
  Object.keys(lines).forEach(key => {
    const i = Number(key);
    if (i === removedIndex) return;
    const newIdx = i > removedIndex ? i - 1 : i;
    next[newIdx] = lines[i];
  });
  return Object.keys(next).length > 0 ? next : undefined;
}

export type TamUngHeaderFieldKey =
  | 'voucherDate'
  | 'customerId'
  | 'creditAccountCode'
  | 'description'
  | 'processingLevel';

export function collectTamUngBannerMessages(
  fieldErrors: TamUngFieldErrors,
  generalErrors: string[] = [],
): string[] {
  const msgs: string[] = [...generalErrors];
  if (fieldErrors.voucherDate) msgs.push(fieldErrors.voucherDate);
  if (fieldErrors.customerId) msgs.push(fieldErrors.customerId);
  if (fieldErrors.creditAccountCode) msgs.push(fieldErrors.creditAccountCode);
  if (fieldErrors.description) msgs.push(fieldErrors.description);
  if (fieldErrors.processingLevel) msgs.push(fieldErrors.processingLevel);
  if (fieldErrors.lines) {
    Object.keys(fieldErrors.lines)
      .map(Number)
      .sort((a, b) => a - b)
      .forEach(idx => {
        const le = fieldErrors.lines![idx];
        if (le?.accountCode) msgs.push(le.accountCode);
        if (le?.debitAmount) msgs.push(le.debitAmount);
      });
  }
  return msgs;
}

export function validateTamUngHeaderField(
  key: TamUngHeaderFieldKey,
  value: string,
): string | undefined {
  switch (key) {
    case 'voucherDate':
      return value?.trim() ? undefined : 'Ngày chứng từ là bắt buộc';
    case 'customerId':
      return value?.trim() ? undefined : 'Người tạm ứng là bắt buộc';
    case 'creditAccountCode':
      return value?.trim() ? undefined : 'TK Có (tạm ứng) là bắt buộc';
    case 'description':
      if (!value?.trim()) return 'Diễn giải là bắt buộc';
      return value.length > VOUCHER_DESCRIPTION_MAX_LENGTH
        ? voucherDescriptionMaxLengthMessage()
        : undefined;
    case 'processingLevel':
      return value?.trim() ? undefined : 'Mức xử lý là bắt buộc';
    default:
      return undefined;
  }
}

export function validateTamUngLineField(
  lineIndex: number,
  key: LineFieldKey,
  line: { accountCode: string; amount: number },
): string | undefined {
  return validateLineField(lineIndex, key, {
    accountCode: line.accountCode,
    debitAmount: line.amount,
  });
}

export function scrollToFirstTamUngFieldError(
  fieldErrors: TamUngFieldErrors,
  tid: (suffix: string) => string,
  bannerId: string,
): void {
  const scroll = (id: string) => {
    setTimeout(() => {
      document.getElementById(id)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }, 120);
  };

  if (fieldErrors.voucherDate) {
    scroll(tid('field-voucherDate'));
    return;
  }
  if (fieldErrors.customerId) {
    scroll(tid('field-customerId'));
    return;
  }
  if (fieldErrors.creditAccountCode) {
    scroll(tid('field-creditAccountCode'));
    return;
  }
  if (fieldErrors.description) {
    scroll(tid('field-description'));
    return;
  }
  if (fieldErrors.processingLevel) {
    scroll(tid('field-processingLevel'));
    return;
  }
  const lineIndices = fieldErrors.lines
    ? Object.keys(fieldErrors.lines).map(Number).sort((a, b) => a - b)
    : [];
  for (const idx of lineIndices) {
    const le = fieldErrors.lines![idx];
    if (le?.accountCode) {
      scroll(tid(`line-${idx}-account`));
      return;
    }
    if (le?.debitAmount) {
      scroll(tid(`line-${idx}-amount`));
      return;
    }
  }
  scroll(bannerId);
}

